package qrspicmd

import (
	"bufio"
	"bytes"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

type sessionEntry struct {
	Type    string          `json:"type"`
	ID      string          `json:"id,omitempty"`
	Cwd     string          `json:"cwd,omitempty"`
	Message *sessionMessage `json:"message,omitempty"`
}

type sessionMessage struct {
	Role       string          `json:"role"`
	Content    json.RawMessage `json:"content"`
	StopReason string          `json:"stopReason,omitempty"`
}

type sessionContentBlock struct {
	Type string `json:"type"`
	Text string `json:"text,omitempty"`
}

func ResolveSessionPath(sessionDir, sessionID, cwd string) (string, error) {
	if strings.TrimSpace(sessionDir) == "" || strings.TrimSpace(sessionID) == "" {
		return "", errors.New("session dir and session id are required")
	}

	if _, err := os.Stat(sessionDir); err != nil {
		if os.IsNotExist(err) {
			return "", fmt.Errorf("session %q not found in %s", sessionID, sessionDir)
		}
		return "", err
	}

	var matches []string
	walkErr := filepath.WalkDir(
		sessionDir,
		func(path string, entry os.DirEntry, err error) error {
			if err != nil {
				return err
			}
			if entry.IsDir() || filepath.Ext(entry.Name()) != ".jsonl" {
				return nil
			}
			header, err := readSessionHeader(path)
			if err != nil {
				return nil
			}
			if header.Type == "session" && header.ID == sessionID &&
				(strings.TrimSpace(cwd) == "" || header.Cwd == cwd) {
				matches = append(matches, path)
			}
			return nil
		},
	)
	if walkErr != nil {
		return "", walkErr
	}

	switch len(matches) {
	case 1:
		return matches[0], nil
	case 0:
		return "", fmt.Errorf("session %q not found in %s", sessionID, sessionDir)
	default:
		return "", fmt.Errorf(
			"session %q matched multiple files in %s",
			sessionID,
			sessionDir,
		)
	}
}

func readSessionHeader(path string) (sessionEntry, error) {
	file, err := os.Open(path)
	if err != nil {
		return sessionEntry{}, err
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 64*1024), 1024*1024)
	if !scanner.Scan() {
		if err := scanner.Err(); err != nil {
			return sessionEntry{}, err
		}
		return sessionEntry{}, errors.New("empty session file")
	}
	var header sessionEntry
	if err := json.Unmarshal(bytes.TrimSpace(scanner.Bytes()), &header); err != nil {
		return sessionEntry{}, err
	}
	return header, nil
}

func ExtractFinalAssistantTextFromSession(path string) (string, error) {
	last, err := extractLastAssistantTextFromSession(path, true)
	if err != nil {
		return "", err
	}
	if last == "" {
		return "", fmt.Errorf(
			"session %s has no assistant text containing qrspi_result",
			path,
		)
	}
	return last, nil
}

func ExtractLastAssistantTextFromSession(path string) (string, error) {
	last, err := extractLastAssistantTextFromSession(path, false)
	if err != nil {
		return "", err
	}
	if last == "" {
		return "", fmt.Errorf("session %s has no assistant text", path)
	}
	return last, nil
}

func extractLastAssistantTextFromSession(
	path string,
	requireQRSPIResult bool,
) (string, error) {
	file, err := os.Open(path)
	if err != nil {
		return "", err
	}
	defer file.Close()

	var last string
	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 64*1024), 1024*1024)
	for scanner.Scan() {
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		var entry sessionEntry
		if err := json.Unmarshal(line, &entry); err != nil {
			continue
		}
		if entry.Type != "message" || entry.Message == nil ||
			entry.Message.Role != "assistant" {
			continue
		}
		if requireQRSPIResult &&
			(entry.Message.StopReason == "error" || entry.Message.StopReason == "aborted") {
			continue
		}
		text := textBlocksFromAssistantMessage(*entry.Message)
		if strings.TrimSpace(text) == "" {
			continue
		}
		if !requireQRSPIResult || strings.Contains(text, "qrspi_result") {
			last = text
		}
	}
	if err := scanner.Err(); err != nil {
		return "", err
	}
	return last, nil
}

func textBlocksFromAssistantMessage(msg sessionMessage) string {
	var blocks []sessionContentBlock
	if err := json.Unmarshal(msg.Content, &blocks); err == nil {
		var parts []string
		for _, block := range blocks {
			if block.Type == "text" && block.Text != "" {
				parts = append(parts, block.Text)
			}
		}
		return strings.Join(parts, "\n")
	}

	var text string
	if err := json.Unmarshal(msg.Content, &text); err == nil {
		return text
	}
	return ""
}

package qrspicmd

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"testing"
)

func TestResolveSessionPathMatchesExactIDInCustomSessionDir(t *testing.T) {
	root := t.TempDir()
	cwd := filepath.Join(root, "repo")
	want := writePiSession(t, root, "target.jsonl", "session-1", cwd)
	writePiSession(t, root, "other.jsonl", "session-2", cwd)

	got, err := ResolveSessionPath(root, "session-1", cwd)
	if err != nil {
		t.Fatalf("ResolveSessionPath error = %v", err)
	}
	if got != want {
		t.Fatalf("path = %q, want %q", got, want)
	}
}

func TestResolveSessionPathFindsPiCwdSubdirectory(t *testing.T) {
	root := t.TempDir()
	cwd := "/tmp/repo"
	want := writePiSession(t, filepath.Join(root, "--tmp-repo--"), "target.jsonl", "session-1", cwd)

	got, err := ResolveSessionPath(root, "session-1", cwd)
	if err != nil {
		t.Fatalf("ResolveSessionPath error = %v", err)
	}
	if got != want {
		t.Fatalf("path = %q, want %q", got, want)
	}
}

func TestResolveSessionPathRejectsMissingOrDuplicate(t *testing.T) {
	root := t.TempDir()
	cwd := "/tmp/repo"
	if _, err := ResolveSessionPath(root, "missing", cwd); err == nil || !strings.Contains(err.Error(), "not found") {
		t.Fatalf("expected missing error, got %v", err)
	}
	writePiSession(t, root, "one.jsonl", "dup", cwd)
	writePiSession(t, root, "two.jsonl", "dup", cwd)
	if _, err := ResolveSessionPath(root, "dup", cwd); err == nil || !strings.Contains(err.Error(), "multiple") {
		t.Fatalf("expected duplicate error, got %v", err)
	}
}

func TestResolveSessionPathDoesNotAcceptSiblingCWD(t *testing.T) {
	root := t.TempDir()
	cwd := "/tmp/repo"
	writePiSession(t, root, "sibling.jsonl", "target", "/tmp/other")

	_, err := ResolveSessionPath(root, "target", cwd)
	if err == nil || !strings.Contains(err.Error(), "not found") {
		t.Fatalf("expected not found for wrong cwd, got %v", err)
	}
}

func TestExtractFinalAssistantTextFromSessionUsesLastAssistantResult(t *testing.T) {
	path := filepath.Join(t.TempDir(), "session.jsonl")
	writeSessionTestFile(t, path, strings.Join([]string{
		sessionHeader("s", "/tmp/repo"),
		assistantLine("first qrspi_result"),
		`{"type":"message","message":{"role":"user","content":"qrspi_result user text"}}`,
		assistantLine("final qrspi_result"),
	}, "\n")+"\n")

	got, err := ExtractFinalAssistantTextFromSession(path)
	if err != nil {
		t.Fatalf("ExtractFinalAssistantTextFromSession error = %v", err)
	}
	if got != "final qrspi_result" {
		t.Fatalf("text = %q", got)
	}
}

func TestExtractFinalAssistantTextFromSessionIgnoresMalformedToolThinkingAndAborted(t *testing.T) {
	path := filepath.Join(t.TempDir(), "session.jsonl")
	writeSessionTestFile(t, path, strings.Join([]string{
		sessionHeader("s", "/tmp/repo"),
		`not-json`,
		`{"type":"message","message":{"role":"assistant","stopReason":"aborted","content":[{"type":"text","text":"aborted qrspi_result"}]}}`,
		`{"type":"message","message":{"role":"assistant","content":[{"type":"thinking","text":"qrspi_result hidden"},{"type":"tool_use","text":"qrspi_result tool"}]}}`,
		assistantLine("visible qrspi_result"),
	}, "\n")+"\n")

	got, err := ExtractFinalAssistantTextFromSession(path)
	if err != nil {
		t.Fatalf("ExtractFinalAssistantTextFromSession error = %v", err)
	}
	if got != "visible qrspi_result" {
		t.Fatalf("text = %q", got)
	}
}

func TestExtractFinalAssistantTextFromSessionErrorsWithoutQRSPIResult(t *testing.T) {
	path := filepath.Join(t.TempDir(), "session.jsonl")
	writeSessionTestFile(t, path, sessionHeader("s", "/tmp/repo")+"\n"+assistantLine("plain text")+"\n")

	_, err := ExtractFinalAssistantTextFromSession(path)
	if err == nil || !strings.Contains(err.Error(), "no assistant text containing qrspi_result") {
		t.Fatalf("expected missing qrspi_result error, got %v", err)
	}
}

func TestTextBlocksFromAssistantMessageAcceptsStringContent(t *testing.T) {
	path := filepath.Join(t.TempDir(), "session.jsonl")
	writeSessionTestFile(t, path, sessionHeader("s", "/tmp/repo")+"\n"+`{"type":"message","message":{"role":"assistant","content":"string qrspi_result"}}`+"\n")

	got, err := ExtractFinalAssistantTextFromSession(path)
	if err != nil {
		t.Fatalf("ExtractFinalAssistantTextFromSession error = %v", err)
	}
	if got != "string qrspi_result" {
		t.Fatalf("text = %q", got)
	}
}

func writePiSession(t *testing.T, sessionRoot, name, sessionID, cwd string, lines ...string) string {
	t.Helper()
	path := filepath.Join(sessionRoot, name)
	content := append([]string{sessionHeader(sessionID, cwd)}, lines...)
	writeSessionTestFile(t, path, strings.Join(content, "\n")+"\n")
	return path
}

func sessionHeader(sessionID, cwd string) string {
	return fmt.Sprintf(`{"type":"session","version":3,"id":%q,"timestamp":"2026-06-20T00:00:00Z","cwd":%q}`, sessionID, cwd)
}

func assistantLine(text string) string {
	return fmt.Sprintf(`{"type":"message","message":{"role":"assistant","stopReason":"endTurn","content":[{"type":"thinking","text":"hidden"},{"type":"text","text":%q}]}}`, text)
}

func writeSessionTestFile(t *testing.T, path, content string) {
	t.Helper()
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
		t.Fatal(err)
	}
}

